mapper.select:
SELECT *
FROM purchase_orders
WHERE store_id = #{storeId}
  AND status IN ('ORDERED', 'DELIVERED')
  AND ordered_at IS NOT NULL
  AND YEAR(ordered_at) = #{year}
  AND MONTH(ordered_at) = #{month}

SELECT * FROM po_weekly_stats WHERE store_id = #{storeId} ORDER BY
base_week ASC total_po_amount DESC base_week DESC
LIMIT #{limit} OFFSET #{offset}

SELECT *
FROM purchase_orders
WHERE store_id = #{storeId}
  AND status IN ('ORDERED', 'DELIVERED')
  AND ordered_at IS NOT NULL
  AND ordered_at >= #{from}
  AND ordered_at < #{to}
